using Microsoft.Xna.Framework;using Microsoft.Xna.Framework.Graphics;using System;using System.Security.Cryptography.X509Certificates;using Terraria;using Terraria.DataStructures;using Terraria.GameContent;using Terraria.GameContent.ItemDropRules;using Terraria.ID;using Terraria.ModLoader;namespace poo.Content.Projectiles&#123;    public class Anima : ModProjectile    &#123;        //设置弹幕主人为player        Player player =&gt; Main.player[Projectile.owner];        public override void SetStaticDefaults()        &#123;            //帧图的总帧数            Main.projFrames[Type] = 3;            //模式2可记录运动轨迹和方向            ProjectileID.Sets.TrailingMode[Type] = 2;            //一共记录几次            ProjectileID.Sets.TrailCacheLength[Type] = 4;        &#125;        public override void SetDefaults()        &#123;            //基础属性            Projectile.width = 71;            Projectile.height = 170;            Projectile.friendly = true;            Projectile.tileCollide = false;            Projectile.timeLeft = 300;            //aiStyle = -1表示不使用原版ai            Projectile.aiStyle = -1;            Projectile.DamageType = DamageClass.Melee;            Projectile.penetrate = -1;            Projectile.ignoreWater = true;                    &#125;        public override void AI()        &#123;            //基础的粒子效果            for (int i = 0; i &lt; 10; i++)            &#123;                Dust dust1 = Dust.NewDustDirect(Projectile.Center - Projectile.Size / 2, 60, 150, 90, 0, 0);                dust1.noGravity = true;            &#125;                            Projectile.ai[0]++;                        if (Projectile.ai[0] == 1)            &#123;                //设置基础速度，表示在单位向量的基础上*150                Projectile.velocity =  Projectile.velocity.SafeNormalize(Vector2.Zero) * 150f;            &#125;            //不断减速            Projectile.velocity *= 0.85f;            //Projectile.velocity = Projectile.velocity.RotatedBy(0.03f);            //让弹幕旋转方向与速度方向一致            Projectile.rotation = Projectile.velocity.ToRotation();            //如果弹幕朝向左边射出（即向量为负），那就翻转一次            if (Projectile.velocity.X &lt; 0)            &#123;                Projectile.direction = Projectile.spriteDirection = -1;                Projectile.rotation += MathHelper.ToRadians(180);            &#125;            else            &#123;                //Projectile.direction = Projectile.spriteDirection = 1;//速度向左时为1，也就是不变                //Projectile.rotation = Projectile.velocity.ToRotation() + 3.1416f;//由于水平反转了我们需要加半圈            &#125;            //原版自带的帧图计时器            Projectile.frameCounter++;            //让Projectile.frame在0到x不停变化            //数字5对应的数越小则变化次数越多            Projectile.frame = (Projectile.frameCounter / 5) % Main.projFrames[Type];            //if (Math.Abs(Projectile.velocity.X) &lt; 0.5f &amp;&amp; Math.Abs(Projectile.velocity.Y) &lt; 0.5f)            //&#123;            //    Projectile.Kill();            //&#125;        &#125;        //开始绘制        public override bool PreDraw(ref Color lightColor)        &#123;            //声明材质            Texture2D texture = TextureAssets.Projectile[Type].Value;            //rectangle表示一个矩形框，这里新定义了一个            //new Rectangle()共四个参数，分别表示为            //框左上角的水平坐标            //框左上角的纵向坐标            //框的宽度            //框的长度            Rectangle rectangle = new Rectangle(                0,                texture.Height / Main.projFrames[Type] * Projectile.frame,                texture.Width,                texture.Height / Main.projFrames[Type]                );                        if (Projectile.ai[1] &lt; 3)            &#123;                Projectile.ai[1]++;            &#125;            //拖尾绘制            for (int i = 0; i &lt; ProjectileID.Sets.TrailCacheLength[Type]; i++)            &#123;                //定义一个从1递减为0的插值                float factor = 1 - (float)i / ProjectileID.Sets.TrailCacheLength[Type];                //oldPos[]数组记录了之前的1位置，但需要长和宽分别要加上弹幕大小的1/2，否则残影会绘制在弹幕的左上角而非中心                //-Main.screenPosition是为了将世界坐标1转化为屏幕坐标                Vector2 oldcenter = Projectile.oldPos[i] + Projectile.Size / 2 - Main.screenPosition;                //主要绘制内容                //共七个参数，分别为                //材质                //绘制的位置，解释见上                //帧图选框                //颜色                //贴图旋转方向                //旋转中心的坐标，这里写为单帧贴图的中心，因此旋转也能围绕中心                //贴图的缩放比例                //图片翻转效果                Main.EntitySpriteDraw(                    texture,                    oldcenter,                     rectangle,                    Color.DarkRed * factor,                    Projectile.oldRot[i],                    new Vector2(texture.Width / 2, texture.Height / 2 / Main.projFrames[Type]),                    new Vector2(1.5f * factor, 1.5f * factor),                    Projectile.direction == 1 ? SpriteEffects.None : SpriteEffects.FlipHorizontally,                    0);            &#125;            //Main.DiscoColor            Main.EntitySpriteDraw(texture,                Projectile.Center - Main.screenPosition,                rectangle,                Color.DarkRed,                Projectile.rotation,                new Vector2(texture.Width / 2, texture.Height / 2 / Main.projFrames[Type]),                new Vector2(1.5f， 1.5f),                Projectile.direction == 1 ? SpriteEffects.None : SpriteEffects.FlipHorizontally,                0                );            //阻止自动绘制；return true会启动自带的绘制            return false;        &#125;    &#125;&#125;

以上为整份Proj.cs的代码。
